const users = $input.all().map(i => i.json);
const flat = Array.isArray(users[0]) ? users[0] : users;
const now = new Date();
const atRisk = [];

for (const user of flat) {
  if (!user.email) continue;
  const createdAt = new Date(user.created_at || user.trial_start);
  const daysSinceCreation = Math.floor((now - createdAt) / (1000 * 60 * 60 * 24));
  const lastActive = user.last_active_at ? new Date(user.last_active_at) : null;
  const daysSinceActive = lastActive ? Math.floor((now - lastActive) / (1000 * 60 * 60 * 24)) : 999;

  let riskType = null;
  let emailSubject = '';
  let emailBody = '';

  // Trial ending in 1-2 days (day 12-13 of 14-day trial)
  if (user.status === 'trial_ending' || (daysSinceCreation >= 12 && daysSinceCreation <= 13 && !user.is_paying)) {
    riskType = 'trial_ending';
    emailSubject = `${user.name || 'Hey'}, your BayFlow trial ends in ${14 - daysSinceCreation} day(s)`;
    emailBody = `Hey ${user.name || 'there'},\n\nHeads up. Your trial wraps up in ${14 - daysSinceCreation} day(s). All the repair orders, customer info, and inspections you've built are still there and ready to go.\n\nIf you want to keep everything, just upgrade here:\nhttps://app.bayflow.com/billing\n\nAnd if something's been holding you back from pulling the trigger, just reply and tell me. I'd rather fix it than lose you.\n\n- Shalin`;
  }
  // Onboarded but not paying
  else if (user.status === 'onboarded_not_paying' && daysSinceCreation > 14) {
    riskType = 'onboarded_not_paying';
    emailSubject = `Quick check-in, ${user.name || 'there'}`;
    emailBody = `Hey ${user.name || 'there'},\n\nI noticed you set up your shop in BayFlow but haven\'t jumped on a paid plan yet. No pressure at all.\n\nBut I\'m curious -- is something not working right? Or did you just get busy? Either way, I\'d love to know. Just reply to this.\n\nIf you\'re ready to go: https://app.bayflow.com/billing\n\n- Shalin`;
  }
  // Inactive 7+ days
  else if (daysSinceActive >= 7 || user.status === 'inactive') {
    riskType = 'inactive_7d';
    emailSubject = `${user.name || 'Hey'}, everything ok?`;
    emailBody = `Hey ${user.name || 'there'},\n\nHaven\'t seen you in BayFlow for a bit. Just wanted to check in. Your data\'s all safe.\n\nA few things you could try when you\'re back:\n- Digital inspections (snap photos, text them to the customer)\n- Track your parts margins on each RO\n- Send invoices right from the app\n\nHere\'s your dashboard: https://app.bayflow.com\n\n- Shalin`;
  }

  if (riskType) {
    atRisk.push({
      email: user.email,
      name: user.name || '',
      user_id: user.user_id || user.id,
      riskType,
      emailSubject,
      emailBody,
      daysSinceCreation,
      daysSinceActive
    });
  }
}

return atRisk.length > 0 ? atRisk.map(u => ({ json: u })) : [{ json: { _empty: true, count: 0 } }];

const body = $('Cancellation Webhook').first().json;
const email = body.email || body.user_email || 'unknown';
const reason = body.reason || body.cancellation_reason || 'No reason given';
const userId = body.user_id || body.id || 'unknown';

const emailBody = `Hey ${body.name || 'there'},

Done. Your BayFlow subscription is cancelled.

Your data stays around for 30 days if you change your mind. Just log back in and it'll all be there.

Honestly, I'd love to know what we could've done better. Even a one-line reply helps. No hard feelings either way.

Good luck with everything,
- Shalin`;

return [{ json: { email, reason, userId, name: body.name || '', emailBody } }];
